import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"Mail management","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/mail-management.md","filePath":"en/guide/mail-management.md"}'),s={name:"en/guide/mail-management.md"};function l(i,t,n,d,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="mail-management" tabindex="-1">Mail management <a class="header-anchor" href="#mail-management" aria-label="Permalink to &quot;Mail management&quot;">​</a></h1><p>The <strong>My emails</strong> page is the heart of Nid. It lets you view, filter and take bulk actions on emails in your Gmail mailbox.</p><hr><h2 id="viewing-emails" tabindex="-1">Viewing emails <a class="header-anchor" href="#viewing-emails" aria-label="Permalink to &quot;Viewing emails&quot;">​</a></h2><p>The page displays the list of your Gmail emails with essential information: sender, subject, date, size, labels and attachment indicator.</p><blockquote><p>📸 <em>Suggested screenshot: My emails page with the email list, filters and action bar</em></p></blockquote><h3 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h3><p>Use the search bar at the top of the page. It supports <strong>native Gmail syntax</strong>:</p><table tabindex="0"><thead><tr><th>Example</th><th>Description</th></tr></thead><tbody><tr><td><code>from:amazon.fr</code></td><td>Emails from Amazon</td></tr><tr><td><code>subject:facture</code></td><td>Emails containing &quot;facture&quot; in the subject</td></tr><tr><td><code>has:attachment larger:5M</code></td><td>Emails with attachments over 5 MB</td></tr><tr><td><code>older_than:1y</code></td><td>Emails older than one year</td></tr><tr><td><code>is:unread from:newsletter</code></td><td>Unread newsletters</td></tr><tr><td><code>label:promotions</code></td><td>Emails in the Promotions label</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: Gmail search bar with suggestions</em></p></blockquote><h3 id="reading-an-email" tabindex="-1">Reading an email <a class="header-anchor" href="#reading-an-email" aria-label="Permalink to &quot;Reading an email&quot;">​</a></h3><p>Click on an email to open it in the <strong>built-in reader</strong>. The reader displays:</p><ul><li>The email body (HTML or plain text)</li><li>Attachments with download option</li><li>Metadata (sender, recipients, date, size)</li></ul><blockquote><p>📸 <em>Suggested screenshot: email reader open with an HTML email and attachments</em></p></blockquote><hr><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><p>Select one or more emails (checkboxes) to bring up the <strong>bulk action bar</strong>:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Delete (trash)</strong></td><td>Sends emails to the Gmail trash (recoverable for 30 days)</td></tr><tr><td><strong>Delete permanently</strong></td><td>Irreversible email deletion</td></tr><tr><td><strong>Archive (Gmail)</strong></td><td>Removes emails from the inbox (INBOX label)</td></tr><tr><td><strong>Mark as read</strong></td><td>Marks all selected emails as read</td></tr><tr><td><strong>Mark as unread</strong></td><td>Marks all selected emails as unread</td></tr><tr><td><strong>Add a label</strong></td><td>Applies a Gmail label to selected emails</td></tr><tr><td><strong>Archive to NAS</strong></td><td>Saves emails as EML files on your NAS</td></tr></tbody></table><blockquote><p>📸 <em>Suggested screenshot: bulk action bar with selected emails</em></p></blockquote><h3 id="select-all" tabindex="-1">Select all <a class="header-anchor" href="#select-all" aria-label="Permalink to &quot;Select all&quot;">​</a></h3><p>Check the box in the table header to select all emails on the current page.</p><h3 id="archive-all-results" tabindex="-1">Archive all results <a class="header-anchor" href="#archive-all-results" aria-label="Permalink to &quot;Archive all results&quot;">​</a></h3><p>The <strong>Archive all</strong> button launches a differential archiving of <strong>all</strong> emails matching the current search, without manual selection. This is an asynchronous job with real-time tracking.</p><hr><h2 id="asynchronous-operations" tabindex="-1">Asynchronous operations <a class="header-anchor" href="#asynchronous-operations" aria-label="Permalink to &quot;Asynchronous operations&quot;">​</a></h2><p>Bulk operations are executed in the background via <strong>jobs</strong>. When you launch an operation:</p><ol><li>A job is created immediately</li><li>A <strong>progress modal</strong> appears with a real-time progress bar</li><li>You can close the modal — the job continues in the background</li><li>Check the <strong>Jobs</strong> page to track all your running jobs</li></ol><blockquote><p>📸 <em>Suggested screenshot: JobProgressModal with progress bar at 60%</em></p></blockquote><div class="tip custom-block"><p class="custom-block-title">Cancellation</p><p>You can cancel a running job from the <strong>Jobs</strong> page. Already processed emails are not rolled back.</p></div><hr><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard shortcuts&quot;">​</a></h2><p>The My emails page supports keyboard shortcuts for quick navigation:</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><kbd>j</kbd></td><td>Next email</td></tr><tr><td><kbd>k</kbd></td><td>Previous email</td></tr><tr><td><kbd>enter</kbd> / <kbd>o</kbd></td><td>Open selected email</td></tr><tr><td><kbd>e</kbd></td><td>Archive (Gmail)</td></tr><tr><td><kbd>&quot;#&quot;</kbd></td><td>Delete (trash)</td></tr><tr><td><kbd>r</kbd></td><td>Mark as read</td></tr><tr><td><kbd>u</kbd></td><td>Mark as unread</td></tr><tr><td><kbd>&quot;/&quot;</kbd></td><td>Focus on the search bar</td></tr><tr><td><kbd>escape</kbd></td><td>Deselect</td></tr></tbody></table><p>Shortcuts are automatically disabled when you are typing in an input field.</p><blockquote><p>📸 <em>Suggested screenshot: keyboard shortcuts banner at the bottom of the My emails page</em></p></blockquote>',35)])])}const u=e(s,[["render",l]]);export{b as __pageData,u as default};
